class Solution:
    def lastVisitedIntegers(self, words: List[str]) -> List[int]:
        nums = []
        res = []
        consecutive_prev = 0

        for word in words:
            if word == "prev":
                consecutive_prev += 1
                k = consecutive_prev
                if len(nums) >= k:
                    res.append(nums[-k])
                else:
                    res.append(-1)
            else:
                consecutive_prev = 0
                nums.append(int(word))

        return res
